var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女と共にいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"부르셨나요? 관리자님?","JPN":"お呼びになりましたか？　管理者様？","ENG":"Did you want to see me, Administrator?","TWN":"管理者，你找我嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"사장실이 아직 답답하신가요? 잠깐 나와 주시면 제가 말끔히…….","JPN":"社長室の風通しが悪いんですか？　ちょっと席を外していただければその隙に私がすっきり……","ENG":"Does your office still feel too stuffy? If you step out for a second, I can clean–","TWN":"你的辦公室還是很悶嗎？還是你先出去一下，我來把裡面……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아, 종신 계약이요? 아하하. 진작 말씀하시지.","JPN":"あ、終身契約ですか？　あはは。そういうことだったんですね。","ENG":"Oh, a lifetime contract? Ah hah hah. Why didn't you say something sooner?","TWN":"蛤？終身契約喔？呵呵呵，你早說嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"회사에서 일하는 건 즐거워요.","JPN":"会社で働くのは楽しいです。","ENG":"I enjoy working here at the company.","TWN":"我很享受在公司做事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"새로운 사람들, 새로운 일, 새로운 볼거리들을 잔뜩 만날 수 있거든요.","JPN":"新しい人、新しい仕事、新しい発見などたくさんの出会いがあります。","ENG":"I get to meet new people, see new things, and have new experiences.","TWN":"因為可以遇到很多新的人、新的工作、新的事。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"혼자 지낸 세월이 너무 길어서 그런 걸지도 모르겠지만…….","JPN":"一人で過ごした時期が長すぎたからかもしれませんが……","ENG":"Maybe it's because I've been alone for so long, but...","TWN":"可能是因為我之前都是一個人生活……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저번에 혼자 흥얼거리면서 말하는 걸 보았다고요?","JPN":"この前独り言を言っているところを見たんですか？","ENG":"You saw me humming and talking to myself one time?","TWN":"你上次有看到我在自言自語喔？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"심지어 물건에 이름을 붙이고 대화하는 모습도?","JPN":"しかも、物に名前を付けて話しかけている姿も？","ENG":"Even when I was giving names to objects and talking to them?","TWN":"甚至還看到我替東西取名字，還和它們對話？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"으으, 더는 놀리지 말아주세요…… 어쩔 수 없는 건데…….","JPN":"ううっ、も、もうからかわないでください……しょうがないんです……","ENG":"Ooh... Please stop teasing me... I can't help it...","TWN":"呃呃，你別再笑話我啦…我也是有苦衷的…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"실내도 환기해야 좋듯이, 정신도 그런 식으로 환기를 해줘야 한단 말이에요.","JPN":"室内に換気する必要があるように、精神にも換気が必要なんですよ。","ENG":"Just like how the interior needs to be ventilated, the mind also needs fresh air in the same way.","TWN":"就像室內要通風一樣，情緒也是需要出口的嘛。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"네? 가보고 싶은 곳이요? 관리자님과 함께…… 가고 싶은 곳이라.","JPN":"はい？　行ってみたいところですか？　管理者様と一緒に……行きたい所、かあ……","ENG":"Huh? Is there a place I want to visit? A place... that I'd like to go with the Administrator…","TWN":"嗯？我想去的地方嗎？和管理者……一起去的地方嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그러면, 건틀렛 경기를 관람하고 싶네요. 당장 출발하자고요? 아하하.","JPN":"それなら、ガントレットの試合を観戦したいです。今すぐ出発するんですか？　あはは。","ENG":"Then, I want to see a Gauntlet match with you. Let's go right away? Ah hah hah.","TWN":"那，我想去看聖鎧比賽！立刻出發嗎？呵呵呵。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"……물론, 노는 건 좋지만 저에겐 아직 해야 할 일이 남아있어요.","JPN":"……もちろん、遊びに行くのはいいのですが、私にはまだやるべきことが残っています。","ENG":"...Of course, I'd love to relax, but I still have some work left to do.","TWN":"……我是很喜歡玩樂，但我還有正事要做。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"철없는 막내로 남아있기엔 전 이미 많은 희생을 겪었어요.","JPN":"自由奔放な末っ子のままでいるには、私はもう、多くの犠牲を見てきました。","ENG":"I've experienced too many sacrifices to still be the immature youngest member.","TWN":"身為不懂事的老么，我已經目睹過許多的犧牲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저는 세상을 위해 싸우다 희생한 그분들을 생각하며 다짐했죠.","JPN":"世の中のために戦って、犠牲になった方々を思いながら、私は誓ったんです。","ENG":"So, I decided on something while thinking of those who sacrificed themselves to save the world.","TWN":"想到他們是為世界而犧牲的，我便下定決心。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"이들의 죽음을 헛되이 하지 않겠다. 이들의 바람을 내가 짊어지겠다.","JPN":"彼らの死を無駄にしない。彼らの望みを私が叶えると。","ENG":"That I won't let their deaths be in vain. That I will carry their wishes with me.","TWN":"我會肩負起他們的心願，絕不會讓他們白白犧牲。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그리고 그들의 의지를 이어 나가기 위해선, 무슨 짓이든 하겠다고.","JPN":"そして、彼らの意志を引き継ぐためには、どんなことでもすると。","ENG":"Also, that I'll do anything to carry out their determination.","TWN":"而且我會盡我所能地，使他們的意志能夠延續下去。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"아하하. 분위기가 너무 무거워졌다고요?","JPN":"あはは。空気が重すぎですか？","ENG":"Ah hah hah. Is it me, or did the air in here get heavy?","TWN":"呵呵呵，突然變得有點嚴肅嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"바람이란, 선선하게 불 때도 있지만 매섭게 몰아칠 때도 있는 법이죠.","JPN":"風は爽やかに吹く時もあれば、厳しく吹きつける時もあります。","ENG":"At times, the wind can blow with a breeze but it can also be fierce.","TWN":"風，可以輕輕吹拂，也可以吹得猛烈。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"저는 그 두 방법을 모두 알고 있을 뿐이에요.","JPN":"私はその両方を知っているだけです。","ENG":"I just happen to know how to do both.","TWN":"而我只是同時知道這二種方法而已。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그건 관리자님도 마찬가지시잖아요?","JPN":"それは管理者様も同じですよね？","ENG":"Isn't it the same for you too, Administrator?","TWN":"管理者不也是一樣嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WIND_VARUNA_NULL_NULL","text":{"KOREA":"그러니 계약서에 서명할게요. 분명 당신이라면 모두의 바람을 짊어질 수 있으실 테니까.","JPN":"だから契約書にサインします。きっとあなたなら、みんなの願いを背負っていけるはずですから。","ENG":"So, I'll sign the contract. I'm sure you are able to carry everyone's wishes.","TWN":"所以我會在契約書上簽名，因為我相信你可以背負所有的希望。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WIND_VARUNA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};